class Solution:
    def divide(self, dividend: int, divisor: int) -> int:
        INT_MIN = -2**31
        INT_MAX = 2**31 - 1

        if dividend == 0:
            return 0

        # Determine the sign of the result
        sign = -1
        if (dividend < 0) == (divisor < 0):
            sign = 1

        a = abs(dividend)
        b = abs(divisor)

        if b > a:
            return 0

        quotient = 0
        while a >= b:
            temp = b
            shift = 0
            # Find the maximum shift such that temp << shift <= a
            while (temp << 1) <= a:
                temp <<= 1
                shift += 1
            quotient += (1 << shift)
            a -= temp

        result = sign * quotient

        # Clamp the result within 32-bit signed integer range
        if result < INT_MIN:
            return INT_MIN
        elif result > INT_MAX:
            return INT_MAX
        else:
            return result
